"use strict";
eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   TEXT: () => (/* binding */ TEXT)\n/* harmony export */ });\nconst TEXT = {\n    es: {\n        projects: {\n            proline: {\n                slug: \"proline\",\n                descripcion: \"Proline es una plataforma de comunidades deportivas construida alrededor de un loop de gamificaci\\xf3n: los fans completan misiones diarias, acumulan puntos y compiten por su pasi\\xf3n. No es una red social tradicional — es un sistema de recompensas para aficionados reales.\",\n                rolYContexto: {\n                    rol: \"Frontend Developer & UI/UX Designer\",\n                    periodo: \"2025 – presente\",\n                    resumen: \"Entr\\xe9 al proyecto con ownership total: desde la definici\\xf3n visual en Figma hasta la implementaci\\xf3n en Next.js. Sin hand-off, sin intermediarios — dise\\xf1o y c\\xf3digo bajo la misma responsabilidad.\"\n                },\n                desafios: [\n                    {\n                        titulo: \"Cero sistema de dise\\xf1o heredado\",\n                        descripcion: \"El producto no ten\\xeda tokens, componentes base ni convenciones de estilo establecidas. Todo ten\\xeda que construirse desde cero sin bloquear el desarrollo de features.\"\n                    },\n                    {\n                        titulo: \"Deuda t\\xe9cnica en estilos\",\n                        descripcion: \"La base de CSS existente era inconsistente y dif\\xedcil de escalar. Migrar a SCSS/BEM sin romper lo ya construido requiri\\xf3 una estrategia incremental y cuidadosa.\"\n                    },\n                    {\n                        titulo: \"Next.js 15 Server / Client Components\",\n                        descripcion: \"Una incompatibilidad cr\\xedtica entre Server y Client Components en CommunityPage generaba errores de hidrataci\\xf3n en producci\\xf3n que eran dif\\xedciles de reproducir localmente.\"\n                    },\n                    {\n                        titulo: \"Datos multi-deporte sin API unificada\",\n                        descripcion: \"El producto consume datos de m\\xfaltiples deportes desde fuentes distintas. Sin una capa de abstracci\\xf3n, cada m\\xf3dulo ten\\xeda l\\xf3gica de integraci\\xf3n dispersa y fr\\xe1gil.\"\n                    },\n                    {\n                        titulo: \"Validaci\\xf3n de producto con m\\xe9tricas reales\",\n                        descripcion: \"El equipo necesitaba tomar decisiones de producto basadas en comportamiento real de usuarios, sin herramientas de analytics ni A/B testing configuradas.\"\n                    }\n                ],\n                decisionesClaveYResultados: [\n                    {\n                        decision: \"Design system desde tokens\",\n                        detalle: \"Establec\\xed los fundamentos del sistema de dise\\xf1o de Proline desde cero: tokens de color (--PlPrimary #00A1E1, --PlAccent #FFAA00), tipograf\\xeda, espaciado y variantes de componente documentadas en Figma y Storybook.\",\n                        resultado: \"Base consistente que permiti\\xf3 escalar a 40+ componentes reutilizables sin regresiones visuales entre m\\xf3dulos.\"\n                    },\n                    {\n                        decision: \"Atomic Design + Storybook como contrato visual\",\n                        detalle: \"Adopt\\xe9 Atomic Design para estructurar la librer\\xeda de componentes y Storybook como entorno de documentaci\\xf3n y testing visual aislado del resto de la app.\",\n                        resultado: \"Reducci\\xf3n de ~18 hrs de desarrollo por sprint al eliminar revisiones manuales de regresi\\xf3n visual y facilitar onboarding de nuevos componentes.\"\n                    },\n                    {\n                        decision: \"Patr\\xf3n BFF con React Query\",\n                        detalle: \"Dise\\xf1\\xe9 una capa Backend for Frontend con React Query para centralizar el fetching, caching y sincronizaci\\xf3n de datos, sacando esa l\\xf3gica de los componentes.\",\n                        resultado: \"Vistas con alta frecuencia de actualizaci\\xf3n sin re-renders innecesarios y una capa de datos predecible y testeable.\"\n                    },\n                    {\n                        decision: \"SportsDataService como abstracci\\xf3n multi-fuente\",\n                        detalle: \"Constru\\xed un servicio centralizado que normaliza datos de distintas APIs deportivas antes de exponerlos al frontend, independientemente del deporte o la fuente.\",\n                        resultado: \"Integraci\\xf3n de nuevos deportes sin tocar la l\\xf3gica de los componentes — el contrato de datos es siempre el mismo.\"\n                    },\n                    {\n                        decision: \"Migraci\\xf3n de GrowthBook a PostHog\",\n                        detalle: \"Evalu\\xe9 las limitaciones de GrowthBook para el volumen y los casos de uso de Proline y lider\\xe9 la migraci\\xf3n a PostHog, integrando analytics y A/B testing en una sola herramienta.\",\n                        resultado: \"El equipo de producto gan\\xf3 visibilidad real del comportamiento de usuarios y la capacidad de lanzar experimentos sin depender de desarrollo para la configuraci\\xf3n.\"\n                    },\n                    {\n                        decision: \"Git worktrees para desarrollo paralelo\",\n                        detalle: \"Adopt\\xe9 Git worktrees para trabajar en m\\xfaltiples branches simult\\xe1neamente sin cambiar de contexto en el mismo directorio de trabajo.\",\n                        resultado: \"Eliminaci\\xf3n de conflictos de estado entre features en curso y ciclos de review m\\xe1s r\\xe1pidos al poder comparar implementaciones en paralelo.\"\n                    }\n                ]\n            },\n            xcamp: {\n                slug: \"xcamp\",\n                descripcion: \"Xcamp es una plataforma educativa con flujos de onboarding y aprendizaje multi-paso. El producto ya estaba en producci\\xf3n con una base de usuarios activa cuando entr\\xe9 al proyecto.\",\n                rolYContexto: {\n                    rol: \"Frontend Angular Developer & UI/UX Designer\",\n                    periodo: \"2025\",\n                    resumen: \"Llegu\\xe9 a un codebase Angular 17 existente con deuda t\\xe9cnica visual, inconsistencias responsivas y sin convenciones claras de componentes. El reto no era construir desde cero — era mejorar sin romper.\"\n                },\n                desafios: [\n                    {\n                        titulo: \"Codebase sin convenciones establecidas\",\n                        descripcion: \"Los componentes existentes ten\\xedan l\\xf3gica duplicada, estilos en l\\xednea mezclados con SCSS y nomenclatura inconsistente, lo que dificultaba entender el alcance de cualquier cambio.\"\n                    },\n                    {\n                        titulo: \"Sin responsividad en flujos cr\\xedticos\",\n                        descripcion: \"Los flujos multi-paso principales no funcionaban correctamente en mobile ni tablet. Eran los flujos de mayor conversi\\xf3n del producto y cualquier cambio ten\\xeda riesgo alto.\"\n                    },\n                    {\n                        titulo: \"Dise\\xf1o y desarrollo desconectados\",\n                        descripcion: \"No exist\\xedan flujos documentados en Figma. Los cambios se implementaban directamente sobre el c\\xf3digo, generando desalineaci\\xf3n entre lo que el dise\\xf1o esperaba y lo que se entregaba.\"\n                    }\n                ],\n                decisionesClaveYResultados: [\n                    {\n                        decision: \"Auditor\\xeda de componentes antes de tocar c\\xf3digo\",\n                        detalle: \"Antes de modificar nada, mape\\xe9 los 30+ componentes existentes para identificar duplicaci\\xf3n de l\\xf3gica, inconsistencias visuales y dependencias ocultas.\",\n                        resultado: \"Un plan de refactor con prioridades claras que evit\\xf3 romper funcionalidad en producci\\xf3n y redujo un 40% la duplicaci\\xf3n de c\\xf3digo CSS.\"\n                    },\n                    {\n                        decision: \"Definir flujos en Figma antes de implementar\",\n                        detalle: \"Establec\\xed el proceso de documentar 8+ flujos end-to-end en Figma antes de escribir una l\\xednea de c\\xf3digo, creando un contrato visual entre dise\\xf1o y desarrollo.\",\n                        resultado: \"Reducci\\xf3n de iteraciones de revisi\\xf3n y alineaci\\xf3n clara de expectativas, acelerando la entrega de cada flujo.\"\n                    },\n                    {\n                        decision: \"Migraci\\xf3n responsiva progresiva con SCSS/BEM\",\n                        detalle: \"Refactoric\\xe9 estilos clave adoptando SCSS con BEM como convenci\\xf3n, y migr\\xe9 los flujos multi-paso cr\\xedticos a dise\\xf1o responsivo mobile-first sin afectar la experiencia desktop.\",\n                        resultado: \"Flujos principales funcionando correctamente en todos los breakpoints y una base de estilos que el equipo adopt\\xf3 como est\\xe1ndar para nuevos desarrollos.\"\n                    },\n                    {\n                        decision: \"Creaci\\xf3n de ~15 componentes nuevos alineados al design system\",\n                        detalle: \"Constru\\xed componentes nuevos siguiendo las convenciones establecidas, documentando su API y casos de uso para reducir la curva de adopci\\xf3n del equipo.\",\n                        resultado: \"Consistencia visual y funcional entre m\\xf3dulos nuevos y existentes, con componentes que el equipo pudo reutilizar sin modificaciones.\"\n                    }\n                ]\n            },\n            freelance: {\n                label: \"proyectos freelance\",\n                clinica: {\n                    slug: \"clinica-pos\",\n                    descripcion: \"App de gesti\\xf3n integral para una cl\\xednica de medicina funcional en CDMX. El cliente operaba completamente en papel: expedientes f\\xedsicos, cobros manuales y sin trazabilidad de inventario.\",\n                    rolYContexto: {\n                        rol: \"Fullstack Developer (freelance)\",\n                        periodo: \"2023 – 2024\",\n                        resumen: \"Fui el \\xfanico desarrollador del proyecto, responsable de la arquitectura, el dise\\xf1o, el desarrollo y el despliegue. El cliente no ten\\xeda experiencia t\\xe9cnica, as\\xed que tambi\\xe9n gestion\\xe9 la definici\\xf3n de requerimientos y el proceso de adopci\\xf3n.\"\n                    },\n                    desafios: [\n                        {\n                            titulo: \"Requerimientos ambiguos y cambiantes\",\n                            descripcion: \"El cliente no sab\\xeda con precisi\\xf3n qu\\xe9 necesitaba hasta que ve\\xeda algo funcionando. Los requerimientos evolucionaban constantemente durante el desarrollo.\"\n                        },\n                        {\n                            titulo: \"Datos m\\xe9dicos sensibles\",\n                            descripcion: \"La app maneja expedientes cl\\xednicos de pacientes reales. El control de acceso y la integridad de los datos no pod\\xedan ser un afterthought — ten\\xedan que estar resueltos desde el dise\\xf1o.\"\n                        },\n                        {\n                            titulo: \"POS con l\\xf3gica de cobro compleja\",\n                            descripcion: \"Los cobros inclu\\xedan pagos parciales, saldos pendientes entre consultas y mezcla de productos con servicios. Una l\\xf3gica incorrecta impactaba directamente en los ingresos del cliente.\"\n                        }\n                    ],\n                    decisionesClaveYResultados: [\n                        {\n                            decision: \"Stack MERN con arquitectura por m\\xf3dulos\",\n                            detalle: \"Eleg\\xed MongoDB por la flexibilidad del esquema para expedientes cl\\xednicos — la estructura de cada paciente variaba seg\\xfan tratamiento. Separ\\xe9 la app en m\\xf3dulos independientes (expedientes, POS, inventario, cobros) para poder entregar valor incremental.\",\n                            resultado: \"Sistema en producci\\xf3n con 4 m\\xf3dulos funcionales, 200+ pacientes registrados y adopci\\xf3n real por parte del equipo de la cl\\xednica.\"\n                        },\n                        {\n                            decision: \"RBAC con JWT desde el inicio\",\n                            detalle: \"Implement\\xe9 control de acceso por roles (m\\xe9dico, recepcionista, admin) usando JWT antes de construir cualquier m\\xf3dulo, para no tener que retrofitear permisos en un sistema ya construido.\",\n                            resultado: \"Datos de pacientes protegidos por rol desde el primer d\\xeda. Cero incidentes de acceso no autorizado durante el periodo de adopci\\xf3n.\"\n                        },\n                        {\n                            decision: \"Sincronizaci\\xf3n en tiempo real entre POS e inventario\",\n                            detalle: \"Dise\\xf1\\xe9 el flujo de venta para que cada ticket actualice el inventario de forma s\\xedncrona antes de confirmar la transacci\\xf3n, evitando inconsistencias de stock.\",\n                            resultado: \"Sincronizaci\\xf3n de tickets menor a 100ms con stock siempre consistente, eliminando discrepancias entre lo vendido y lo disponible.\"\n                        }\n                    ]\n                },\n                coLabora: {\n                    slug: \"co-labora\",\n                    descripcion: \"Plataforma de descubrimiento y renta de espacios de coworking. Los anfitriones publican sus espacios y los usuarios los encuentran, reservan y pagan directamente en la plataforma.\",\n                    rolYContexto: {\n                        rol: \"Fullstack Developer (freelance)\",\n                        periodo: \"2023 – 2024\",\n                        resumen: \"Llev\\xe9 el proyecto completo de Figma a producci\\xf3n como \\xfanico desarrollador. Tom\\xe9 decisiones de arquitectura, integr\\xe9 servicios de terceros y gestion\\xe9 el despliegue.\"\n                    },\n                    desafios: [\n                        {\n                            titulo: \"M\\xfaltiples integraciones de terceros cr\\xedticas\",\n                            descripcion: \"Google Maps, Stripe y SendGrid ten\\xedan que funcionar de forma confiable y coordinada. Un fallo en cualquiera de ellas romp\\xeda flujos centrales del producto.\"\n                        },\n                        {\n                            titulo: \"Gesti\\xf3n de im\\xe1genes a escala\",\n                            descripcion: \"Los anfitriones suben m\\xfaltiples fotos por espacio. Sin optimizaci\\xf3n, el tiempo de carga y el costo de almacenamiento escalar\\xedan r\\xe1pidamente.\"\n                        },\n                        {\n                            titulo: \"Flujo de reserva con estados complejos\",\n                            descripcion: \"Una reserva pasa por m\\xfaltiples estados (disponible, pendiente, confirmada, cancelada) con l\\xf3gica de negocio diferente en cada uno y notificaciones asociadas.\"\n                        }\n                    ],\n                    decisionesClaveYResultados: [\n                        {\n                            decision: \"AWS S3 + Sharp para im\\xe1genes\",\n                            detalle: \"Implement\\xe9 un pipeline de carga que redimensiona autom\\xe1ticamente las im\\xe1genes con Sharp antes de subirlas a S3, generando variantes optimizadas para distintos contextos de visualizaci\\xf3n.\",\n                            resultado: \"Tiempos de carga reducidos significativamente y costo de almacenamiento controlado desde el primer usuario.\"\n                        },\n                        {\n                            decision: \"Stripe con manejo expl\\xedcito de estados de pago\",\n                            detalle: \"Implement\\xe9 el flujo de Stripe manejando expl\\xedcitamente cada estado posible (succeeded, failed, requires_action) con feedback claro al usuario y actualizaci\\xf3n autom\\xe1tica del estado de reserva.\",\n                            resultado: \"Cero reservas confirmadas con pago fallido. Flujo de checkout robusto con recuperaci\\xf3n autom\\xe1tica de errores transitorios.\"\n                        },\n                        {\n                            decision: \"SendGrid para notificaciones transaccionales\",\n                            detalle: \"Configur\\xe9 notificaciones autom\\xe1ticas en cada cambio de estado de reserva: confirmaci\\xf3n, recordatorio 24 hrs antes, cancelaci\\xf3n y solicitud de rese\\xf1a post-estancia.\",\n                            resultado: \"Comunicaci\\xf3n automatizada entre anfitriones y usuarios sin intervenci\\xf3n manual, reduciendo fricciones del proceso de reserva.\"\n                        }\n                    ]\n                }\n            }\n        }\n    },\n    en: {\n        projects: {\n            proline: {\n                slug: \"proline\",\n                description: \"Proline is a sports communities platform built around a gamification loop: fans complete daily missions, earn points and compete for their passion. It is not a traditional social network — it is a rewards system for real supporters.\",\n                roleAndContext: {\n                    role: \"Frontend Developer & UI/UX Designer\",\n                    period: \"2025 – present\",\n                    summary: \"I joined the project with full ownership: from visual definition in Figma to implementation in Next.js. No hand-off, no intermediaries — design and code under the same responsibility.\"\n                },\n                challenges: [\n                    {\n                        title: \"No inherited design system\",\n                        description: \"The product had no tokens, no base components and no established style conventions. Everything had to be built from scratch without blocking feature development.\"\n                    },\n                    {\n                        title: \"Technical debt in styles\",\n                        description: \"The existing CSS base was inconsistent and hard to scale. Migrating to SCSS/BEM without breaking what was already built required a careful, incremental strategy.\"\n                    },\n                    {\n                        title: \"Next.js 15 Server / Client Components\",\n                        description: \"A critical incompatibility between Server and Client Components in CommunityPage was causing hydration errors in production that were hard to reproduce locally.\"\n                    },\n                    {\n                        title: \"Multi-sport data with no unified API\",\n                        description: \"The product consumes data from multiple sports across different sources. Without an abstraction layer, each module had scattered and fragile integration logic.\"\n                    },\n                    {\n                        title: \"Product validation with real metrics\",\n                        description: \"The team needed to make product decisions based on real user behavior, with no analytics or A/B testing tools configured.\"\n                    }\n                ],\n                keyDecisionsAndResults: [\n                    {\n                        decision: \"Design system built from tokens\",\n                        detail: \"I established the foundations of Proline's design system from scratch: color tokens (--PlPrimary #00A1E1, --PlAccent #FFAA00), typography, spacing and component variants documented in Figma and Storybook.\",\n                        result: \"A consistent foundation that allowed scaling to 40+ reusable components without visual regressions across modules.\"\n                    },\n                    {\n                        decision: \"Atomic Design + Storybook as a visual contract\",\n                        detail: \"I adopted Atomic Design to structure the component library and Storybook as a documentation and visual testing environment isolated from the rest of the app.\",\n                        result: \"A reduction of ~18 dev hours per sprint by eliminating manual visual regression reviews and simplifying new component onboarding.\"\n                    },\n                    {\n                        decision: \"BFF pattern with React Query\",\n                        detail: \"I designed a Backend for Frontend layer with React Query to centralize data fetching, caching and synchronization, moving that logic out of the components.\",\n                        result: \"High-frequency update views with no unnecessary re-renders and a predictable, testable data layer.\"\n                    },\n                    {\n                        decision: \"SportsDataService as a multi-source abstraction\",\n                        detail: \"I built a centralized service that normalizes data from different sports APIs before exposing it to the frontend, regardless of sport or source.\",\n                        result: \"New sports can be integrated without touching component logic — the data contract is always the same.\"\n                    },\n                    {\n                        decision: \"Migration from GrowthBook to PostHog\",\n                        detail: \"I assessed GrowthBook's limitations for Proline's volume and use cases and led the migration to PostHog, consolidating analytics and A/B testing into a single tool.\",\n                        result: \"The product team gained real visibility into user behavior and the ability to launch experiments without depending on development for configuration.\"\n                    },\n                    {\n                        decision: \"Git worktrees for parallel development\",\n                        detail: \"I adopted Git worktrees to work on multiple branches simultaneously without switching context in the same working directory.\",\n                        result: \"Eliminated state conflicts between in-progress features and faster review cycles by being able to compare implementations in parallel.\"\n                    }\n                ]\n            },\n            xcamp: {\n                slug: \"xcamp\",\n                description: \"Xcamp is an educational platform with multi-step onboarding and learning flows. The product was already in production with an active user base when I joined.\",\n                roleAndContext: {\n                    role: \"Frontend Angular Developer & UI/UX Designer\",\n                    period: \"2025\",\n                    summary: \"I joined an existing Angular 17 codebase carrying visual technical debt, responsive inconsistencies and no clear component conventions. The challenge was not to build from scratch — it was to improve without breaking.\"\n                },\n                challenges: [\n                    {\n                        title: \"Codebase with no established conventions\",\n                        description: \"Existing components had duplicated logic, inline styles mixed with SCSS and inconsistent naming, making it hard to understand the scope of any change.\"\n                    },\n                    {\n                        title: \"No responsive support on critical flows\",\n                        description: \"The main multi-step flows did not work correctly on mobile or tablet. These were the highest-conversion flows in the product and any change carried high risk.\"\n                    },\n                    {\n                        title: \"Design and development disconnected\",\n                        description: \"No flows were documented in Figma. Changes were implemented directly in code, creating misalignment between what design expected and what was delivered.\"\n                    }\n                ],\n                keyDecisionsAndResults: [\n                    {\n                        decision: \"Component audit before touching code\",\n                        detail: \"Before modifying anything, I mapped all 30+ existing components to identify logic duplication, visual inconsistencies and hidden dependencies.\",\n                        result: \"A prioritized refactor plan that avoided breaking production functionality and reduced CSS code duplication by 40%.\"\n                    },\n                    {\n                        decision: \"Define flows in Figma before implementing\",\n                        detail: \"I established the process of documenting 8+ end-to-end flows in Figma before writing a single line of code, creating a visual contract between design and development.\",\n                        result: \"Fewer review iterations and clear expectation alignment, accelerating delivery for each flow.\"\n                    },\n                    {\n                        decision: \"Progressive responsive migration with SCSS/BEM\",\n                        detail: \"I refactored key styles adopting SCSS with BEM as convention and migrated the critical multi-step flows to mobile-first responsive design without affecting the desktop experience.\",\n                        result: \"Main flows working correctly at every breakpoint and a style foundation the team adopted as the standard for new development.\"\n                    },\n                    {\n                        decision: \"Creation of ~15 new components aligned to the design system\",\n                        detail: \"I built new components following the established conventions, documenting their API and use cases to reduce the team's adoption curve.\",\n                        result: \"Visual and functional consistency between new and existing modules, with components the team could reuse without modifications.\"\n                    }\n                ]\n            },\n            freelance: {\n                label: \"freelance projects\",\n                clinica: {\n                    slug: \"clinica-pos\",\n                    description: \"A comprehensive management app for a functional-medicine clinic in Mexico City. The client operated entirely on paper: physical records, manual billing and no inventory tracking.\",\n                    roleAndContext: {\n                        role: \"Fullstack Developer (freelance)\",\n                        period: \"2023 – 2024\",\n                        summary: \"I was the sole developer on the project, responsible for architecture, design, development and deployment. Since the client had no technical background, I also managed requirements definition and the adoption process.\"\n                    },\n                    challenges: [\n                        {\n                            title: \"Ambiguous and evolving requirements\",\n                            description: \"The client did not know precisely what they needed until they saw something working. Requirements kept evolving throughout the build.\"\n                        },\n                        {\n                            title: \"Sensitive medical data\",\n                            description: \"The app handles real patient clinical records. Access control and data integrity could not be an afterthought — they had to be solved at the design level.\"\n                        },\n                        {\n                            title: \"POS with complex billing logic\",\n                            description: \"Billing included partial payments, outstanding balances across visits and a mix of products and services. Incorrect logic directly impacted the client's revenue.\"\n                        }\n                    ],\n                    keyDecisionsAndResults: [\n                        {\n                            decision: \"MERN stack with modular architecture\",\n                            detail: \"I chose MongoDB for schema flexibility with clinical records — each patient's structure varied by treatment. I split the app into independent modules (records, POS, inventory, billing) to deliver incremental value.\",\n                            result: \"A production system with 4 functional modules, 200+ registered patients and real adoption by the clinic's team.\"\n                        },\n                        {\n                            decision: \"RBAC with JWT from day one\",\n                            detail: \"I implemented role-based access control (doctor, receptionist, admin) using JWT before building any module, to avoid retrofitting permissions into an already-built system.\",\n                            result: \"Patient data protected by role from day one. Zero unauthorized access incidents during the adoption period.\"\n                        },\n                        {\n                            decision: \"Real-time sync between POS and inventory\",\n                            detail: \"I designed the sales flow to update inventory synchronously before confirming the transaction, preventing stock inconsistencies.\",\n                            result: \"Ticket sync under 100ms with always-consistent stock, eliminating discrepancies between what was sold and what was available.\"\n                        }\n                    ]\n                },\n                coLabora: {\n                    slug: \"co-labora\",\n                    description: \"A coworking space discovery and rental platform. Hosts publish their spaces and users find, book and pay directly on the platform.\",\n                    roleAndContext: {\n                        role: \"Fullstack Developer (freelance)\",\n                        period: \"2023 – 2024\",\n                        summary: \"I took the entire project from Figma to production as the sole developer, making architecture decisions, integrating third-party services and managing deployment.\"\n                    },\n                    challenges: [\n                        {\n                            title: \"Multiple critical third-party integrations\",\n                            description: \"Google Maps, Stripe and SendGrid had to work reliably and in coordination. A failure in any of them broke core product flows.\"\n                        },\n                        {\n                            title: \"Image management at scale\",\n                            description: \"Hosts upload multiple photos per space. Without optimization, load times and storage costs would scale quickly.\"\n                        },\n                        {\n                            title: \"Booking flow with complex states\",\n                            description: \"A booking moves through multiple states (available, pending, confirmed, cancelled) with different business logic at each stage and associated notifications.\"\n                        }\n                    ],\n                    keyDecisionsAndResults: [\n                        {\n                            decision: \"AWS S3 + Sharp for images\",\n                            detail: \"I built an upload pipeline that automatically resizes images with Sharp before pushing them to S3, generating optimized variants for different display contexts.\",\n                            result: \"Significantly reduced load times and controlled storage costs from the first user.\"\n                        },\n                        {\n                            decision: \"Stripe with explicit payment state handling\",\n                            detail: \"I implemented the Stripe flow explicitly handling every possible state (succeeded, failed, requires_action) with clear user feedback and automatic booking status updates.\",\n                            result: \"Zero bookings confirmed with a failed payment. Robust checkout flow with automatic recovery from transient errors.\"\n                        },\n                        {\n                            decision: \"SendGrid for transactional notifications\",\n                            detail: \"I configured automatic notifications on every booking state change: confirmation, 24-hour reminder, cancellation and post-stay review request.\",\n                            result: \"Automated communication between hosts and users with no manual intervention, reducing friction in the booking process.\"\n                        }\n                    ]\n                }\n            }\n        }\n    }\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./hifi/projects/projects.jsx\n");

